      // between our check above and the listener registration
      const timeout = setTimeout(() => resolve(), 5000);
      proc.on("exit", () => {
        clearTimeout(timeout);
        resolve();
      });
      killProcessGroup(proc, "SIGKILL");
    }),
);
await Promise.all(exitPromises);
